/* Dashboard */
let cS=null;const buildStat=(color,icon,value,label)=>`<div class="stat-card c-${color}"><div class="stat-icon-wrap">${ic(icon,20)}</div><div class="stat-value">${value}</div><div class="stat-label">${label}</div></div>`;const renderDash=()=>{const inv=(G('invoices')||[]).filter(i=>i.status!=='cancelled');const tbls=G('tables')||[],ords=G('orders')||[];const ts=td();const tInv=inv.filter(i=>i.date&&i.date.startsWith(ts));const tRev=tInv.reduce((s,i)=>s+(i.grandTotal||0),0);const tOrd=ords.filter(o=>o.orderTime&&o.orderTime.startsWith(ts));const occ=tbls.filter(t=>t.status==='occupied').length;let sh='';if(can('dashboardFull')){const exp=G('expenses')||[];const tExp=exp.filter(e=>e.date&&e.date.startsWith(ts)).reduce((s,e)=>s+(e.amount||0),0);const prods=G('products')||[];let tP=0;tOrd.forEach(o=>(o.items||[]).forEach(it=>{const p=prods.find(x=>x.id===it.productId);if(p)tP+=((p.price||0)-(p.cost||0))*it.qty}));tP-=tExp;sh=buildStat('gold','trending-up',fC(tRev),'مبيعات اليوم')+buildStat('red','receipt',fC(tExp),'مصروفات اليوم')+buildStat('teal','wallet',fC(tP),'صافي الربح')+buildStat('blue','clipboard-list',tOrd.length,'طلبات اليوم')}else{sh=buildStat('gold','trending-up',fC(tRev),'مبيعات اليوم')+buildStat('teal','clipboard-list',tOrd.length,'طلبات اليوم')+buildStat('blue','users',`${occ}/${tbls.length}`,'طاولات مشغولة')+buildStat('purple','file-text',tInv.length,'فواتير اليوم')}document.getElementById('dashStats').innerHTML=sh;ri();document.getElementById('dDate').textContent=new Date().toLocaleDateString('ar-IQ',{weekday:'long',year:'numeric',month:'long',day:'numeric'});const days=[],sales=[];for(let i=6;i>=0;i--){const d=new Date();d.setDate(d.getDate()-i);const ds=d.toISOString().split('T')[0];days.push(d.toLocaleDateString('ar-IQ',{weekday:'short',day:'numeric'}));sales.push(inv.filter(v=>v.date&&v.date.startsWith(ds)).reduce((s,v)=>s+(v.grandTotal||0),0))}const ctx=document.getElementById('cSales').getContext('2d');if(cS)cS.destroy();const gr=ctx.createLinearGradient(0,0,0,240);gr.addColorStop(0,'rgba(212,175,55,0.18)');gr.addColorStop(1,'rgba(212,175,55,0)');cS=new Chart(ctx,{type:'line',data:{labels:days,datasets:[{data:sales,borderColor:'#D4AF37',backgroundColor:gr,borderWidth:2.5,tension:.42,fill:true,pointBackgroundColor:'#D4AF37',pointRadius:5,pointBorderColor:'#0B0E14',pointBorderWidth:2}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},scales:{x:{grid:{color:'rgba(255,255,255,0.03)',drawBorder:false},ticks:{color:'#8E9AAF',font:{family:'Cairo',size:11}}},y:{grid:{color:'rgba(255,255,255,0.03)',drawBorder:false},ticks:{color:'#8E9AAF',font:{family:'Inter'}}}}}});const acts=G('act')||[];document.getElementById('actFd').innerHTML=acts.length?acts.slice(0,8).map(a=>`<div class="activity-item"><div class="activity-dot" style="background:${a.color}"></div><div style="flex:1"><div class="activity-text">${esc(a.txt)}</div><div class="activity-time">${fT(a.time)} · ${fD(a.time)}</div></div></div>`).join(''):'<div style="text-align:center;padding:32px;color:var(--text-3)">لا توجد نشاطات</div>'};

/* ═══════════════════════════════════════════
   FLOOR PLAN — Full Drag + Zoom Support
═══════════════════════════════════════════ */
let fpCanvas=null,fpSelectedId=null,fpTimer=null,fpZoomLevel=1;

const renderFloorPlan=()=>{
  const tools=document.getElementById('fpTools');
  let th='';
  if(can('addTable'))th+=`<button class="btn btn-gold btn-sm" onclick="openAddTableM()">${ic('plus')}<span>طاولة</span></button>`;
  th+=`<button class="btn btn-ghost btn-sm" onclick="renderFloorPlan()">${ic('refresh-cw')}<span>تحديث</span></button>`;
  tools.innerHTML=th;
  const tbls=G('tables')||[];
  document.getElementById('tblSum').textContent=`متاحة: ${tbls.filter(t=>t.status==='free').length} · مشغولة: ${tbls.filter(t=>t.status==='occupied').length} · إجمالي: ${tbls.length}`;
  document.getElementById('fpInfo').innerHTML=can('editLayout')?'<b>اسحب</b> لترتيب · عجلة الماوس للتكبير · <b>Alt+سحب</b> لتحريك المشهد':'اضغط على طاولة للخيارات';

  const box=document.getElementById('fpBox');
  const canvasW=Math.max(box.clientWidth-20,800,Math.ceil(Math.sqrt(tbls.length||1))*220+200);
  const canvasH=Math.max(600,Math.ceil((tbls.length||1)/Math.max(1,Math.ceil(Math.sqrt(tbls.length||1))))*220+200);

  document.getElementById('fpCanvas').width=canvasW;
  document.getElementById('fpCanvas').height=canvasH;

  if(fpCanvas){fpCanvas.dispose();fpCanvas=null}

  fpCanvas=new fabric.Canvas('fpCanvas',{
    selection:false,
    backgroundColor:'transparent',
    preserveObjectStacking:true,
    width:canvasW,
    height:canvasH
  });

  fpCanvas.on('mouse:wheel',function(opt){
    const delta=opt.e.deltaY;
    let zoom=fpCanvas.getZoom();
    zoom*=0.999**delta;
    if(zoom>3)zoom=3;
    if(zoom<0.3)zoom=0.3;
    fpCanvas.zoomToPoint({x:opt.e.offsetX,y:opt.e.offsetY},zoom);
    fpZoomLevel=zoom;
    document.getElementById('fpZoomLbl').textContent=Math.round(zoom*100)+'%';
    opt.e.preventDefault();
    opt.e.stopPropagation();
  });

  let isPanning=false,lastPosX=0,lastPosY=0;
  fpCanvas.on('mouse:down',function(opt){
    const evt=opt.e;
    if(evt.altKey||evt.button===1){
      isPanning=true;
      fpCanvas.selection=false;
      lastPosX=evt.clientX;
      lastPosY=evt.clientY;
      evt.preventDefault();
      return;
    }
    if(!opt.target){fpClearSelection();return}
    if(opt.target.tableId)fpSelectTable(opt.target.tableId);
  });

  fpCanvas.on('mouse:move',function(opt){
    if(isPanning){
      const e=opt.e;
      const vpt=fpCanvas.viewportTransform;
      vpt[4]+=e.clientX-lastPosX;
      vpt[5]+=e.clientY-lastPosY;
      lastPosX=e.clientX;
      lastPosY=e.clientY;
      fpCanvas.requestRenderAll();
    }
  });

  fpCanvas.on('mouse:up',function(){isPanning=false;fpCanvas.selection=false});

  fpCanvas.on('object:modified',e=>{
    if(!can('editLayout'))return;
    if(e.target&&e.target.tableGroupId){
      UP('tables',e.target.tableGroupId,{x:Math.round(e.target.left),y:Math.round(e.target.top)});
    }
  });

  drawAllTables();
  ri();

  if(fpTimer)clearInterval(fpTimer);
  fpTimer=setInterval(()=>{
    if(document.getElementById('tables').classList.contains('active')){
      drawAllTables();
      if(fpSelectedId)fpSelectTable(fpSelectedId,true);
    }
  },5000);
};

const fpZoom=(delta)=>{
  if(!fpCanvas)return;
  let zoom=fpCanvas.getZoom()+delta;
  if(zoom>3)zoom=3;if(zoom<0.3)zoom=0.3;
  const center=fpCanvas.getCenter();
  fpCanvas.zoomToPoint({x:center.left,y:center.top},zoom);
  fpZoomLevel=zoom;
  document.getElementById('fpZoomLbl').textContent=Math.round(zoom*100)+'%';
};

const fpFitAll=()=>{
  if(!fpCanvas)return;
  const tbls=G('tables')||[];if(!tbls.length)return;
  let minX=Infinity,minY=Infinity,maxX=-Infinity,maxY=-Infinity;
  tbls.forEach(t=>{const x=t.x||100,y=t.y||100;if(x-100<minX)minX=x-100;if(y-100<minY)minY=y-100;if(x+100>maxX)maxX=x+100;if(y+100>maxY)maxY=y+100});
  const box=document.getElementById('fpBox');
  const bw=box.clientWidth-40,bh=box.clientHeight-40;
  let zoom=Math.min(bw/(maxX-minX),bh/(maxY-minY),2);
  if(zoom<0.3)zoom=0.3;
  fpCanvas.setViewportTransform([zoom,0,0,zoom,-minX*zoom+20,-minY*zoom+20]);
  fpZoomLevel=zoom;
  document.getElementById('fpZoomLbl').textContent=Math.round(zoom*100)+'%';
};

const drawAllTables=()=>{
  if(!fpCanvas)return;
  const tbls=G('tables')||[],sess=G('sessions')||[];
  const vpt=[...fpCanvas.viewportTransform];
  fpCanvas.clear();
  tbls.forEach(t=>{const s=sess.find(x=>x.id===t.sessionId);fpCanvas.add(buildTG(t,s,t.id===fpSelectedId))});
  fpCanvas.setViewportTransform(vpt);
  fpCanvas.renderAll();
};

const buildTG=(t,session,isSel)=>{const sc={free:'#2DD4BF',occupied:'#D4AF37',reserved:'#60A5FA'}[t.status]||'#8E9AAF';const objs=[],cap=t.capacity||4;const cF='#2A2416',cS2='#1A1610',cSz=20,tF='#5D3A1E',tE='#3D2614';const addCh=(cx,cy)=>{objs.push(new fabric.Rect({left:cx+1,top:cy+2,width:cSz,height:cSz,rx:6,ry:6,fill:'rgba(0,0,0,0.5)',originX:'center',originY:'center'}));objs.push(new fabric.Rect({left:cx,top:cy,width:cSz,height:cSz,rx:6,ry:6,fill:cF,stroke:cS2,strokeWidth:1.5,originX:'center',originY:'center'}))};if(t.shape==='round'){const r=44,cd=r+24;for(let i=0;i<cap;i++){const a=(i/cap)*Math.PI*2-Math.PI/2;addCh(Math.cos(a)*cd,Math.sin(a)*cd)}objs.push(new fabric.Circle({left:3,top:5,radius:r,fill:'rgba(0,0,0,0.55)',originX:'center',originY:'center'}));objs.push(new fabric.Circle({left:0,top:0,radius:r,fill:tF,stroke:sc,strokeWidth:2.5,originX:'center',originY:'center'}));objs.push(new fabric.Circle({left:0,top:0,radius:r-7,fill:'transparent',stroke:tE,strokeWidth:1,opacity:.6,originX:'center',originY:'center'}))}else if(t.shape==='rect'){const tw=150,th2=74,cps=Math.ceil(cap/2),rem=cap-cps;for(let i=0;i<cps;i++){addCh(-tw/2+(tw/(cps+1))*(i+1),-th2/2-16)}for(let i=0;i<rem;i++){addCh(-tw/2+(tw/(rem+1))*(i+1),th2/2+16)}objs.push(new fabric.Rect({left:3,top:5,width:tw,height:th2,rx:10,ry:10,fill:'rgba(0,0,0,0.55)',originX:'center',originY:'center'}));objs.push(new fabric.Rect({left:0,top:0,width:tw,height:th2,rx:10,ry:10,fill:tF,stroke:sc,strokeWidth:2.5,originX:'center',originY:'center'}));objs.push(new fabric.Line([-tw/2+16,0,tw/2-16,0],{stroke:tE,strokeWidth:1,opacity:.5}))}else{const ts2=80,cc=Math.min(cap,4);const pos=[{x:0,y:-ts2/2-16},{x:0,y:ts2/2+16},{x:-ts2/2-16,y:0},{x:ts2/2+16,y:0}];for(let i=0;i<cc;i++)addCh(pos[i].x,pos[i].y);objs.push(new fabric.Rect({left:3,top:5,width:ts2,height:ts2,rx:8,ry:8,fill:'rgba(0,0,0,0.55)',originX:'center',originY:'center'}));objs.push(new fabric.Rect({left:0,top:0,width:ts2,height:ts2,rx:8,ry:8,fill:tF,stroke:sc,strokeWidth:2.5,originX:'center',originY:'center'}));objs.push(new fabric.Line([-ts2/2+12,0,ts2/2-12,0],{stroke:tE,strokeWidth:1,opacity:.5}))}objs.push(new fabric.Text(String(t.number),{left:0,top:-4,fontSize:24,fontFamily:'Playfair Display,serif',fontWeight:'800',fill:'#FFF',originX:'center',originY:'center',shadow:'rgba(0,0,0,0.7) 0 2px 3px'}));objs.push(new fabric.Text(`${t.capacity} Guests`,{left:0,top:16,fontSize:9,fontFamily:'Inter,sans-serif',fontWeight:'500',fill:'rgba(255,255,255,0.65)',originX:'center',originY:'center',charSpacing:50}));if(t.status==='occupied'&&session){const diff=Math.floor((Date.now()-new Date(session.startTime))/1000),h=Math.floor(diff/3600),m=Math.floor((diff%3600)/60);const ts3=`${h?h+'h ':''}${m}m`,tOff=t.shape==='round'?-80:(t.shape==='rect'?-70:-76);objs.push(new fabric.Rect({left:0,top:tOff,width:72,height:24,rx:12,ry:12,fill:'#D4AF37',originX:'center',originY:'center',shadow:'rgba(212,175,55,0.4) 0 4px 12px'}));objs.push(new fabric.Text(`● ${ts3}`,{left:0,top:tOff,fontSize:11,fontFamily:'Inter,sans-serif',fontWeight:'700',fill:'#0B0E14',originX:'center',originY:'center'}))}if(isSel){const rR=t.shape==='round'?74:(t.shape==='rect'?100:64);objs.push(new fabric.Circle({left:0,top:0,radius:rR,fill:'transparent',stroke:'#D4AF37',strokeWidth:2,strokeDashArray:[6,5],originX:'center',originY:'center',opacity:.9}))}const g=new fabric.Group(objs,{left:t.x||100,top:t.y||100,hasControls:false,hasBorders:false,lockRotation:true,lockScalingX:true,lockScalingY:true,selectable:can('editLayout'),hoverCursor:'pointer',subTargetCheck:false});g.tableId=t.id;g.tableGroupId=t.id;return g};

const fpSelectTable=(id,silent=false)=>{fpSelectedId=id;const tbls=G('tables')||[],sess=G('sessions')||[];const t=tbls.find(x=>x.id===id);if(!t)return;if(!silent)drawAllTables();const s=sess.find(x=>x.id===t.sessionId);const stLbl={free:'متاحة',occupied:'مشغولة',reserved:'محجوزة'}[t.status]||t.status;document.getElementById('fpSpTitle').textContent=`طاولة ${t.number}`;let info=`${stLbl} · ${t.capacity} أشخاص`;if(s){const d=Math.floor((Date.now()-new Date(s.startTime))/1000),h=Math.floor(d/3600),m=Math.floor((d%3600)/60);info+=` · منذ ${h?h+'س ':''}${m}د · ${fC(s.total||0)}`}document.getElementById('fpSpInfo').textContent=info;let ah='';if(t.status==='free'){if(can('startSession'))ah+=`<button class="btn btn-teal btn-sm" onclick="startSess(${t.id})">${ic('play')}<span>بدء جلسة</span></button>`;if(can('addOrder'))ah+=`<button class="btn btn-ghost btn-sm" onclick="openPOS(${t.id},false)">${ic('plus')}<span>طلب</span></button>`}else if(t.status==='occupied'){if(can('addOrder'))ah+=`<button class="btn btn-teal btn-sm" onclick="openPOS(${t.id},false)">${ic('plus')}<span>طلب</span></button>`;if(can('pay'))ah+=`<button class="btn btn-gold btn-sm" onclick="openPOS(${t.id},true)">${ic('credit-card')}<span>تسديد</span></button>`;if(can('endSession')&&!can('pay'))ah+=`<button class="btn btn-blue btn-sm" onclick="requestBill(${t.id})">${ic('receipt')}<span>فاتورة</span></button>`}if(can('editLayout'))ah+=`<button class="btn btn-ghost btn-sm" onclick="openEditTableM(${t.id})">${ic('edit-3')}</button>`;if(can('deleteTable')&&t.status==='free')ah+=`<button class="btn btn-danger btn-sm" onclick="confirmDelTable(${t.id})">${ic('trash-2')}</button>`;document.getElementById('fpSpActs').innerHTML=ah;document.getElementById('fpSelPanel').classList.add('on');ri()};
const fpClearSelection=()=>{fpSelectedId=null;document.getElementById('fpSelPanel').classList.remove('on');drawAllTables()};
const openAddTableM=()=>{const tbls=G('tables')||[],nn=tbls.length?Math.max(...tbls.map(t=>t.number))+1:1;modal(`<div class="modal-title">إضافة طاولة</div><div class="form-row"><div class="input-group"><label>الرقم</label><div class="input-wrap"><input type="number" id="ntNum" value="${nn}"></div></div><div class="input-group"><label>السعة</label><div class="input-wrap"><input type="number" id="ntCap" value="4" min="1"></div></div></div><div class="input-group"><label>الشكل</label><div class="input-wrap"><select id="ntShape"><option value="square">مربع</option><option value="rect">مستطيل</option><option value="round">دائري</option></select></div></div><div class="modal-footer"><button class="btn btn-ghost" onclick="closeM()">إلغاء</button><button class="btn btn-gold" onclick="addTable()">إضافة</button></div>`)};
const addTable=()=>{const num=parseInt(document.getElementById('ntNum').value),cap=parseInt(document.getElementById('ntCap').value),shape=document.getElementById('ntShape').value;if(!num||num<1){toast('رقم غير صحيح','err');return}const tbls=G('tables')||[];if(tbls.find(t=>t.number===num)){toast('الرقم مستخدم','err');return}const cols=Math.ceil(Math.sqrt(tbls.length+1));const row=Math.floor(tbls.length/cols);const col=tbls.length%cols;tbls.push({id:NI('tables'),number:num,capacity:cap,status:'free',sessionId:null,x:150+col*200,y:150+row*200,shape});S('tables',tbls);addA(`إضافة طاولة ${num}`,'#2DD4BF');toast('تمت الإضافة');closeM();renderFloorPlan()};
const openEditTableM=id=>{const t=(G('tables')||[]).find(x=>x.id===id);if(!t)return;modal(`<div class="modal-title">تعديل طاولة ${t.number}</div><div class="form-row"><div class="input-group"><label>الرقم</label><div class="input-wrap"><input type="number" id="etNum" value="${t.number}"></div></div><div class="input-group"><label>السعة</label><div class="input-wrap"><input type="number" id="etCap" value="${t.capacity}" min="1"></div></div></div><div class="input-group"><label>الشكل</label><div class="input-wrap"><select id="etShape"><option value="square" ${t.shape==='square'?'selected':''}>مربع</option><option value="rect" ${t.shape==='rect'?'selected':''}>مستطيل</option><option value="round" ${t.shape==='round'?'selected':''}>دائري</option></select></div></div><div class="modal-footer"><button class="btn btn-ghost" onclick="closeM()">إلغاء</button><button class="btn btn-gold" onclick="saveEditTable(${id})">حفظ</button></div>`)};const saveEditTable=id=>{UP('tables',id,{number:parseInt(document.getElementById('etNum').value),capacity:parseInt(document.getElementById('etCap').value),shape:document.getElementById('etShape').value});toast('تم التعديل');closeM();renderFloorPlan()};const confirmDelTable=id=>{modal(`<div class="modal-title">حذف طاولة</div><div class="modal-subtitle">هل أنت متأكد؟</div><div class="modal-footer"><button class="btn btn-ghost" onclick="closeM()">إلغاء</button><button class="btn btn-danger" onclick="doDelTable(${id})">حذف</button></div>`)};const doDelTable=id=>{DL('tables',id);toast('تم الحذف');closeM();fpClearSelection();renderFloorPlan()};

/* Sessions & POS */
const startSess=id=>{if(!can('startSession')){toast('لا صلاحية','err');return}const tbls=G('tables')||[],t=tbls.find(x=>x.id===id);if(!t||t.status!=='free'){toast('غير متاحة','err');return}const sess=G('sessions')||[],s={id:NI('sessions'),tableId:id,startTime:new Date().toISOString(),lastOrderTime:null,total:0,staffId:CU?.id};sess.push(s);S('sessions',sess);UP('tables',id,{status:'occupied',sessionId:s.id});addA(`بدء جلسة طاولة ${t.number}`,'#2DD4BF');toast(`بدء جلسة الطاولة ${t.number}`);renderFloorPlan();setTimeout(()=>fpSelectTable(id),100)};const endSess=tableId=>{const tbls=G('tables')||[],sess=G('sessions')||[],t=tbls.find(x=>x.id===tableId);if(!t)return;const s=sess.find(x=>x.id===t.sessionId);if(!s)return;const i=G('ri')||{},tax=(i.tax||0)/100,sub=s.total||0,taxA=Math.round(sub*tax),grand=sub+taxA;const inv=G('invoices')||[];inv.push({id:NI('invoices'),sessionId:s.id,tableId,tableNumber:t.number,subtotal:sub,tax:taxA,grandTotal:grand,paymentMethod:'cash',status:'paid',date:new Date().toISOString(),staffId:CU?.id});S('invoices',inv);S('sessions',sess.filter(x=>x.id!==s.id));UP('tables',tableId,{status:'free',sessionId:null});addA(`تسديد طاولة ${t.number} — ${fC(grand)}`,'#D4AF37');toast(`تم التسديد: ${fC(grand)}`);closePOS();fpClearSelection();renderFloorPlan()};const requestBill=tableId=>{addA(`طلب فاتورة`,'#60A5FA');toast('تم إرسال طلب الفاتورة')};

let pTbl=null,pItm={},pChk=false;const openPOS=(tableId,chk=false)=>{if(chk&&!can('pay')){toast('لا صلاحية','err');return}if(!chk&&!can('addOrder')){toast('لا صلاحية','err');return}pTbl=tableId;pItm={};pChk=chk;const t=(G('tables')||[]).find(x=>x.id===tableId),sess=G('sessions')||[],s=t?sess.find(x=>x.id===t.sessionId):null;document.getElementById('posT').textContent=`طاولة ${t?.number} — ${chk?'تسديد':'طلبات'}`;document.getElementById('posM').textContent=s?`بدأت: ${fT(s.startTime)} · ${fC(s.total)}`:'جلسة جديدة';document.getElementById('posSnd').style.display=chk?'none':'';document.getElementById('posRh').textContent=chk?'طلبات الجلسة':'الطلب الحالي';const mb=document.getElementById('pMnBtn');mb.innerHTML=chk?`${ic('credit-card')}<span>تسديد نقداً</span>`:`${ic('send')}<span>إرسال للمطبخ</span>`;if(document.getElementById('posSearch'))document.getElementById('posSearch').value='';renderPProds('');renderPOrd();document.getElementById('posPanel').style.display='flex';ri()};const closePOS=()=>{document.getElementById('posPanel').style.display='none';pTbl=null;pItm={}};let curPosCat='';const renderPProds=(cat)=>{if(cat!==undefined)curPosCat=cat;const pr=G('products')||[],search=(document.getElementById('posSearch')?.value||'').toLowerCase();const cats=[...new Set(pr.map(p=>p.category))];document.getElementById('pCats').innerHTML=`<button class="cat-pill${!curPosCat?' on':''}" onclick="renderPProds('')">الكل</button>`+cats.map(c=>`<button class="cat-pill${curPosCat===c?' on':''}" onclick="renderPProds('${esc(c)}')">${esc(c)}</button>`).join('');let lst=curPosCat?pr.filter(p=>p.category===curPosCat):pr;if(search)lst=lst.filter(p=>p.name.toLowerCase().includes(search)||(p.code||'').includes(search));document.getElementById('pGrid').innerHTML=lst.length?lst.map(p=>{const img=p.image?`<img src="${p.image}" alt="">`:ic('image-off',38);return`<div class="pos-product" onclick="addOrd(${p.id})"><div class="pos-product-img">${img}</div><div class="pos-product-body"><div class="pos-product-code">${esc(p.code||'—')}</div><div class="pos-product-name">${esc(p.name)}</div><div class="pos-product-price">${fC(p.price)}</div></div></div>`}).join(''):'<div style="grid-column:1/-1;text-align:center;padding:40px;color:var(--text-3)">لا توجد منتجات</div>';ri()};const addOrd=id=>{const p=(G('products')||[]).find(x=>x.id===id);if(!p)return;pItm[id]?pItm[id].qty++:(pItm[id]={...p,qty:1});const ch=document.querySelector('.cart-header');if(ch){ch.classList.remove('bump');void ch.offsetWidth;ch.classList.add('bump')}renderPOrd()};const chgQ=(id,d)=>{if(!pItm[id])return;pItm[id].qty+=d;if(pItm[id].qty<=0)delete pItm[id];renderPOrd()};const renderPOrd=()=>{const newItems=Object.values(pItm),el=document.getElementById('pOrdL');let html='';if(pChk&&pTbl){const t=(G('tables')||[]).find(x=>x.id===pTbl),sess=G('sessions')||[],s=t?sess.find(x=>x.id===t.sessionId):null;if(s){(G('orders')||[]).filter(o=>o.sessionId===s.id).forEach(o=>(o.items||[]).forEach(it=>{html+=`<div class="cart-item old"><div class="cart-item-name">${esc(it.name)}</div><div class="qty-num">×${it.qty}</div><div class="cart-item-sub">${fC(it.price*it.qty)}</div></div>`}))}}if(newItems.length)html+=newItems.map(x=>`<div class="cart-item"><div class="cart-item-name">${esc(x.name)}</div><div class="qty-ctrl"><button class="qty-btn" onclick="chgQ(${x.id},-1)">${ic('minus',12)}</button><span class="qty-num">${x.qty}</span><button class="qty-btn" onclick="chgQ(${x.id},1)">${ic('plus',12)}</button></div><div class="cart-item-sub">${fC(x.price*x.qty)}</div></div>`).join('');if(!html)html=`<div class="cart-empty">${ic('shopping-bag',36)}<div style="margin-top:10px">اضغط على منتج</div></div>`;el.innerHTML=html;ri();const i=G('ri')||{},tax=(i.tax||0)/100;let sub=newItems.reduce((s,x)=>s+x.price*x.qty,0);if(pChk&&pTbl){const t=(G('tables')||[]).find(x=>x.id===pTbl),sess=G('sessions')||[],s=t?sess.find(x=>x.id===t.sessionId):null;if(s)sub+=s.total||0}const tA=Math.round(sub*tax),gr2=sub+tA;document.getElementById('pSub').textContent=fC(sub);document.getElementById('pTxL').textContent=`ضريبة ${i.tax||0}%`;document.getElementById('pTxV').textContent=fC(tA);document.getElementById('pGrd').textContent=fC(gr2)};const pMain=()=>pChk?checkout():sendOrd();const sendOrd=()=>{const it=Object.values(pItm);if(!it.length){toast('أضف منتجات','err');return}if(!pTbl)return;const tbls=G('tables')||[],t=tbls.find(x=>x.id===pTbl);if(!t)return;if(t.status==='free'){if(can('startSession'))startSess(pTbl);else{toast('لا صلاحية','err');return}}const uT=(G('tables')||[]).find(x=>x.id===pTbl),sess=G('sessions')||[],s=sess.find(x=>x.id===uT?.sessionId);if(!s){toast('لا توجد جلسة','err');return}const ords=G('orders')||[],tot=it.reduce((s,x)=>s+x.price*x.qty,0);ords.push({id:NI('orders'),sessionId:s.id,tableId:pTbl,tableNumber:uT.number,items:it.map(x=>({productId:x.id,name:x.name,qty:x.qty,price:x.price,cost:x.cost,code:x.code})),total:tot,status:'pending',orderTime:new Date().toISOString(),staffId:CU?.id});S('orders',ords);UP('sessions',s.id,{total:(s.total||0)+tot,lastOrderTime:new Date().toISOString()});addA(`طلب — طاولة ${uT.number}`,'#A78BFA');toast(`تم إرسال ${it.length} صنف للمطبخ`);closePOS();renderFloorPlan()};const checkout=()=>{if(!pTbl)return;const t=(G('tables')||[]).find(x=>x.id===pTbl);if(!t||t.status!=='occupied'){toast('لا توجد جلسة','err');return}if(Object.keys(pItm).length>0){toast('أرسل الطلب أولاً','err');return}endSess(pTbl)};
/* Kitchen */
let kitTimer=null;const renderKitchen=()=>{const ords=G('orders')||[],pnd=ords.filter(o=>o.status==='pending');document.getElementById('kitCnt').textContent=pnd.length?`${pnd.length} طلب معلق`:'المطبخ هادئ';const rc=()=>{document.getElementById('kitGrid').innerHTML=pnd.length?pnd.map(o=>{const el=Math.floor((Date.now()-new Date(o.orderTime))/1000),em=Math.floor(el/60),es=el%60,isLate=em>=15;return`<div class="kitchen-ticket ${isLate?'late':''}"><div class="ticket-header"><div><div class="ticket-table">طاولة ${o.tableNumber||'—'}</div><div class="ticket-elapsed">${em}:${String(es).padStart(2,'0')}</div></div><div class="ticket-time">${fT(o.orderTime)}</div></div><div class="ticket-body">${(o.items||[]).map(it=>`<div class="ticket-item"><span class="ticket-item-name">${esc(it.name)}</span><span class="ticket-qty">×${it.qty}</span></div>`).join('')}</div><div class="ticket-footer"><span class="ticket-status">${ic(isLate?'alert-triangle':'clock')}${isLate?'متأخر':'قيد التحضير'}</span>${can('markReady')?`<button class="btn btn-teal btn-sm" onclick="mReady(${o.id})">${ic('check')}<span>جاهز</span></button>`:''}</div></div>`}).join(''):`<div class="kitchen-empty">${ic('utensils-crossed',56)}<div style="margin-top:16px">لا توجد طلبات</div></div>`;ri()};rc();if(kitTimer)clearInterval(kitTimer);kitTimer=setInterval(()=>{if(document.getElementById('kitchen').classList.contains('active'))rc()},1000)};const mReady=id=>{if(!can('markReady')){toast('لا صلاحية','err');return}UP('orders',id,{status:'ready',readyTime:new Date().toISOString()});addA(`طلب #${id} جاهز`,'#2DD4BF');toast('الطلب جاهز');renderKitchen()};
/* Products */
const compressImage=(file,maxW=500,maxH=500,quality=.82)=>new Promise((resolve,reject)=>{if(!file)return reject();const reader=new FileReader();reader.onload=e=>{const img=new Image();img.onload=()=>{let w=img.width,h=img.height;if(w>maxW||h>maxH){const r=Math.min(maxW/w,maxH/h);w=Math.round(w*r);h=Math.round(h*r)}const c=document.createElement('canvas');c.width=w;c.height=h;c.getContext('2d').drawImage(img,0,0,w,h);resolve(c.toDataURL('image/jpeg',quality))};img.onerror=()=>reject();img.src=e.target.result};reader.onerror=()=>reject();reader.readAsDataURL(file)});const renderProds=()=>{const pr=G('products')||[],cats=[...new Set(pr.map(p=>p.category))];const catSel=document.getElementById('prodFilterCat');if(catSel){const cur=catSel.value;catSel.innerHTML=`<option value="">كل الفئات</option>`+cats.map(c=>`<option value="${esc(c)}" ${c===cur?'selected':''}>${esc(c)}</option>`).join('')}const search=(document.getElementById('prodSearch')?.value||'').toLowerCase(),fcat=document.getElementById('prodFilterCat')?.value||'';let filtered=pr.filter(p=>{if(search&&!p.name.toLowerCase().includes(search)&&!(p.code||'').toLowerCase().includes(search))return false;if(fcat&&p.category!==fcat)return false;return true});const body=document.getElementById('prodBd');if(!filtered.length){body.innerHTML=`<tr><td colspan="8"><div class="empty-state">${ic('package',48)}<div class="empty-state-title">لا توجد منتجات</div></div></td></tr>`;ri();return}body.innerHTML=filtered.map(p=>{const profit=(p.price||0)-(p.cost||0),margin=p.price?Math.round((profit/p.price)*100):0;const img=p.image?`<img src="${p.image}" alt="">`:ic('image-off');return`<tr><td><span class="prod-code">${esc(p.code||'—')}</span></td><td><div class="prod-thumb">${img}</div></td><td><div class="prod-name">${esc(p.name)}</div></td><td><span class="badge badge-muted">${esc(p.category||'—')}</span></td><td class="prod-num" style="color:var(--text-2)">${(p.cost||0).toLocaleString()}</td><td class="prod-num" style="color:var(--gold);font-weight:700">${(p.price||0).toLocaleString()}</td><td class="prod-num"><strong style="color:var(--teal)">${profit.toLocaleString()}</strong><div style="font-size:11px;color:var(--text-3);margin-top:2px">${margin}%</div></td><td><div style="display:flex;gap:6px;justify-content:flex-end"><button class="btn btn-ghost btn-sm" onclick="openProdM(${p.id})">${ic('edit-3')}</button><button class="btn btn-danger btn-sm" onclick="confDel('products',${p.id},'${esc(p.name).replace(/'/g,"\\'")}')">${ic('trash-2')}</button></div></td></tr>`}).join('');ri()};let tempImg=null;const openProdM=(id=null)=>{const pr=G('products')||[],p=id?pr.find(x=>x.id===id):null;tempImg=p?.image||null;const cats=['رئيسي','جانبي','مشروبات','حلويات','مقبلات'];let nc=p?.code||'';if(!id){const mx=pr.reduce((m,x)=>{const n=parseInt(x.code||'0');return n>m?n:m},0);nc=String(mx+1).padStart(3,'0')}modalWide(`<div class="modal-title">${p?'تعديل منتج':'إضافة منتج جديد'}</div><div style="display:grid;grid-template-columns:220px 1fr;gap:24px"><div><label style="display:block;font-size:12px;font-weight:600;color:var(--text-2);margin-bottom:8px">صورة المنتج</label><div class="img-upload ${tempImg?'has-img':''}" id="imgBox" onclick="document.getElementById('imgFile').click()">${tempImg?`<img src="${tempImg}" alt=""><button class="img-remove" onclick="removeProdImage(event)">${ic('x')}</button>`:`<div class="img-placeholder">${ic('upload-cloud',32)}<div class="img-placeholder-text">اختر صورة</div><div class="img-placeholder-hint">JPG / PNG · حتى 2MB</div></div>`}</div><input type="file" id="imgFile" accept="image/*" style="display:none" onchange="handleProdImage(event)"></div><div><div class="form-row"><div class="input-group"><label>رقم المنتج</label><div class="input-wrap"><input id="pCode" value="${esc(nc)}"></div></div><div class="input-group"><label>الفئة</label><div class="input-wrap"><select id="pCat">${cats.map(c=>`<option value="${c}" ${p?.category===c?'selected':''}>${c}</option>`).join('')}</select></div></div></div><div class="input-group"><label>اسم المنتج</label><div class="input-wrap"><input id="pN" value="${esc(p?.name||'')}"></div></div><div class="form-row"><div class="input-group"><label>سعر التكلفة</label><div class="input-wrap"><input type="number" id="pC" value="${p?.cost||''}"></div></div><div class="input-group"><label>سعر البيع</label><div class="input-wrap"><input type="number" id="pP" value="${p?.price||''}"></div></div></div></div></div><div class="modal-footer"><button class="btn btn-ghost" onclick="closeM()">إلغاء</button><button class="btn btn-gold" onclick="saveProd(${id||'null'})">${ic('save')}<span>حفظ</span></button></div>`)};const handleProdImage=async e=>{const file=e.target.files[0];if(!file)return;if(file.size>2*1024*1024){toast('الحجم كبير','err');return}try{tempImg=await compressImage(file);const box=document.getElementById('imgBox');box.classList.add('has-img');box.innerHTML=`<img src="${tempImg}" alt=""><button class="img-remove" onclick="removeProdImage(event)">${ic('x')}</button>`;ri();toast('تم التحميل')}catch{toast('فشل التحميل','err')}};const removeProdImage=e=>{e.stopPropagation();tempImg=null;const box=document.getElementById('imgBox');box.classList.remove('has-img');box.innerHTML=`<div class="img-placeholder">${ic('upload-cloud',32)}<div class="img-placeholder-text">اختر صورة</div><div class="img-placeholder-hint">JPG / PNG · حتى 2MB</div></div>`;document.getElementById('imgFile').value='';ri()};const saveProd=id=>{const name=document.getElementById('pN').value.trim(),code=document.getElementById('pCode').value.trim();if(!name){toast('أدخل الاسم','err');return}if(!code){toast('أدخل الرقم','err');return}if((G('products')||[]).find(x=>x.code===code&&x.id!==id)){toast(`الرقم ${code} مستخدم`,'err');return}const d={code,name,cost:parseFloat(document.getElementById('pC').value)||0,price:parseFloat(document.getElementById('pP').value)||0,category:document.getElementById('pCat').value,image:tempImg};if(id){UP('products',id,d);toast('تم التعديل')}else{const a=G('products')||[];a.push({id:NI('products'),...d});S('products',a);toast('تمت الإضافة')}addA(`${id?'تعديل':'إضافة'} منتج: ${name}`,'#A78BFA');tempImg=null;closeM();renderProds()};

/* ═══════════════════════════════════════════
   RESERVATIONS — With Tabs
═══════════════════════════════════════════ */
let currentResTab='pending';
const setResTab=t=>{currentResTab=t;document.querySelectorAll('[data-restab]').forEach(x=>x.classList.remove('on'));document.querySelector(`[data-restab="${t}"]`)?.classList.add('on');renderResContent()};

const renderRes=()=>{
  const res=G('reservations')||[];
  const pending=res.filter(r=>r.status==='pending').length;
  const confirmed=res.filter(r=>r.status==='confirmed').length;
  const cancelled=res.filter(r=>r.status==='cancelled').length;
  const today=res.filter(r=>r.date===td()).length;
  document.getElementById('resStats').innerHTML=buildStat('gold','clock',pending,'طلبات معلقة')+buildStat('teal','check-circle',confirmed,'مؤكدة')+buildStat('red','x-circle',cancelled,'ملغاة')+buildStat('blue','calendar',today,'حجوزات اليوم');
  document.getElementById('resSubtitle').textContent=`${res.length} حجز إجمالي · ${today} اليوم`;
  ri();renderResContent();
};

const renderResContent=()=>{
  const res=G('reservations')||[],tbls=G('tables')||[],el=document.getElementById('resLst');
  let filtered=res;
  if(currentResTab==='pending')filtered=res.filter(r=>r.status==='pending');
  else if(currentResTab==='confirmed')filtered=res.filter(r=>r.status==='confirmed');
  if(!filtered.length){const emptyMsg={pending:'لا توجد طلبات حجز معلقة',confirmed:'لا توجد حجوزات مؤكدة',all:'لا توجد حجوزات'}[currentResTab];el.innerHTML=`<div class="empty-state">${ic('calendar-x',48)}<div class="empty-state-title">${emptyMsg}</div></div>`;ri();return}
  const srt=[...filtered].sort((a,b)=>a.date>b.date?1:a.date<b.date?-1:a.time>b.time?1:-1);
  const scls={confirmed:'badge-teal',pending:'badge-gold',cancelled:'badge-red'},slbl={confirmed:'مؤكد',pending:'معلق',cancelled:'ملغي'};
  el.innerHTML=srt.map(r=>{const t=tbls.find(x=>x.id===r.tableId);const isToday=r.date===td();let qa='';if(r.status==='pending')qa=`<button class="btn btn-teal btn-sm" onclick="quickConfirmRes(${r.id})">${ic('check',14)}<span>تأكيد</span></button><button class="btn btn-danger btn-sm" onclick="quickCancelRes(${r.id})">${ic('x',14)}<span>رفض</span></button>`;return`<div class="reservation-card ${isToday?'res-today':''}"><div class="res-time-box"><div class="res-time">${r.time}</div><div class="res-date">${r.date}</div>${isToday?'<div class="res-today-badge">اليوم</div>':''}</div><div class="res-info"><div class="res-name">${esc(r.customerName)}</div><div class="res-meta"><span>${ic('phone',12)} ${esc(r.phone)}</span><span>${ic('armchair',12)} ${t?'طاولة '+t.number:'—'}</span><span>${ic('users',12)} ${r.guests}</span>${r.notes?`<span>${ic('file-text',12)} ${esc(r.notes)}</span>`:''}</div></div><div class="res-actions"><span class="badge ${scls[r.status]||'badge-muted'}">${slbl[r.status]||r.status}</span><div style="display:flex;gap:6px;flex-wrap:wrap">${qa}<button class="btn btn-ghost btn-sm" onclick="openResM(${r.id})">${ic('edit-3')}</button><button class="btn btn-danger btn-sm" onclick="confDel('reservations',${r.id},'${esc(r.customerName).replace(/'/g,"\\'")}')">${ic('trash-2')}</button></div></div></div>`}).join('');ri();
};

const quickConfirmRes=id=>{UP('reservations',id,{status:'confirmed'});addA('تأكيد حجز','#2DD4BF');toast('تم تأكيد الحجز');renderRes()};
const quickCancelRes=id=>{UP('reservations',id,{status:'cancelled'});addA('إلغاء حجز','#F04F4F');toast('تم إلغاء الحجز');renderRes()};

const openResM=(id=null)=>{const res=G('reservations')||[],tbls=G('tables')||[],r=id?res.find(x=>x.id===id):null;modal(`<div class="modal-title">${r?'تعديل الحجز':'حجز جديد'}</div><div class="form-row"><div class="input-group"><label>اسم العميل</label><div class="input-wrap"><input id="rN" value="${esc(r?.customerName||'')}"></div></div><div class="input-group"><label>الهاتف</label><div class="input-wrap"><input id="rPh" value="${esc(r?.phone||'')}"></div></div></div><div class="form-row"><div class="input-group"><label>التاريخ</label><div class="input-wrap"><input type="date" id="rD" value="${r?.date||td()}"></div></div><div class="input-group"><label>الوقت</label><div class="input-wrap"><input type="time" id="rT" value="${r?.time||'12:00'}"></div></div></div><div class="form-row"><div class="input-group"><label>الطاولة</label><div class="input-wrap"><select id="rTb">${tbls.map(t=>`<option value="${t.id}" ${r?.tableId===t.id?'selected':''}>طاولة ${t.number}</option>`).join('')}</select></div></div><div class="input-group"><label>الأشخاص</label><div class="input-wrap"><input type="number" id="rG" value="${r?.guests||2}" min="1"></div></div></div><div class="form-row"><div class="input-group"><label>الحالة</label><div class="input-wrap"><select id="rSt"><option value="pending" ${r?.status==='pending'?'selected':''}>معلق</option><option value="confirmed" ${r?.status==='confirmed'?'selected':''}>مؤكد</option><option value="cancelled" ${r?.status==='cancelled'?'selected':''}>ملغي</option></select></div></div><div class="input-group"><label>ملاحظات</label><div class="input-wrap"><input id="rNt" value="${esc(r?.notes||'')}"></div></div></div><div class="modal-footer"><button class="btn btn-ghost" onclick="closeM()">إلغاء</button><button class="btn btn-gold" onclick="saveRes(${id||'null'})">حفظ</button></div>`)};const saveRes=id=>{const nm=document.getElementById('rN').value.trim();if(!nm){toast('أدخل الاسم','err');return}const d={customerName:nm,phone:document.getElementById('rPh').value.trim(),date:document.getElementById('rD').value,time:document.getElementById('rT').value,tableId:parseInt(document.getElementById('rTb').value),guests:parseInt(document.getElementById('rG').value)||1,status:document.getElementById('rSt').value,notes:document.getElementById('rNt').value.trim()};if(id){UP('reservations',id,d);toast('تم التعديل')}else{const a=G('reservations')||[];a.push({id:NI('reservations'),...d});S('reservations',a);toast('تمت الإضافة')}closeM();renderRes()};

/* ═══════════════════════════════════════════
   REPORTS — Professional with Period Filter
═══════════════════════════════════════════ */
let cR=null,cRBar=null,cRCompare=null,currentRepTab='overview';
let repPeriodMode='monthly',repMonth=new Date().getMonth(),repYear=new Date().getFullYear();
const monthNames=['يناير','فبراير','مارس','أبريل','مايو','يونيو','يوليو','أغسطس','سبتمبر','أكتوبر','نوفمبر','ديسمبر'];

const initRepPeriodControls=()=>{const mSel=document.getElementById('repMonth'),ySel=document.getElementById('repYear');mSel.innerHTML=monthNames.map((m,i)=>`<option value="${i}" ${i===repMonth?'selected':''}>${m}</option>`).join('');const curY=new Date().getFullYear();let yO='';for(let y=curY+1;y>=2020;y--)yO+=`<option value="${y}" ${y===repYear?'selected':''}>${y}</option>`;ySel.innerHTML=yO;updateRepPeriodUI()};

const setRepPeriodMode=mode=>{repPeriodMode=mode;document.querySelectorAll('[data-pmode]').forEach(x=>x.classList.remove('on'));document.querySelector(`[data-pmode="${mode}"]`)?.classList.add('on');updateRepPeriodUI();onRepPeriodChange()};

const updateRepPeriodUI=()=>{document.getElementById('repMonth').style.display=repPeriodMode==='monthly'?'':'none';document.getElementById('repPeriodLabel').textContent=repPeriodMode==='monthly'?`${monthNames[repMonth]} ${repYear}`:`سنة ${repYear}`};

const onRepPeriodChange=()=>{repMonth=parseInt(document.getElementById('repMonth').value);repYear=parseInt(document.getElementById('repYear').value);updateRepPeriodUI();if(currentRepTab==='overview')renderRepOverview();else if(currentRepTab==='invoices')renderAllInv();else if(currentRepTab==='expenses')renderExpenses()};

const filterByPeriod=(arr,dateField='date')=>arr.filter(item=>{const d=item[dateField];if(!d)return false;const dt=new Date(d);return repPeriodMode==='monthly'?dt.getMonth()===repMonth&&dt.getFullYear()===repYear:dt.getFullYear()===repYear});

const setReportTab=t=>{currentRepTab=t;document.querySelectorAll('[data-rtab]').forEach(x=>x.classList.remove('on'));document.querySelector(`[data-rtab="${t}"]`)?.classList.add('on');['repOverview','repInvoices','repExpenses'].forEach(id=>document.getElementById(id).style.display='none');if(t==='overview'){document.getElementById('repOverview').style.display='';renderRepOverview()}else if(t==='invoices'){document.getElementById('repInvoices').style.display='';renderAllInv()}else if(t==='expenses'){document.getElementById('repExpenses').style.display='';renderExpenses()}};

const renderReports=()=>{document.getElementById('tabExp').style.display=can('manageExpenses')?'':'none';initRepPeriodControls();setReportTab(currentRepTab==='expenses'&&!can('manageExpenses')?'overview':currentRepTab)};

const calcPP=(filteredOrders)=>{const ords=filteredOrders||G('orders')||[];const prods=G('products')||[],st={};ords.forEach(o=>(o.items||[]).forEach(it=>{const p=prods.find(x=>x.id===it.productId);if(!p)return;if(!st[it.productId])st[it.productId]={id:p.id,name:p.name,qtySold:0,revenue:0,profit:0};st[it.productId].qtySold+=it.qty;st[it.productId].revenue+=(it.price||0)*it.qty;const cost=it.cost!==undefined?it.cost:(p.cost||0);st[it.productId].profit+=((it.price||0)-cost)*it.qty}));return Object.values(st)};

const renderRepOverview=()=>{
  const allInv=(G('invoices')||[]).filter(i=>i.status!=='cancelled');
  const inv=filterByPeriod(allInv);
  const ords=filterByPeriod(G('orders')||[],'orderTime');
  const tR=inv.reduce((s,i)=>s+(i.grandTotal||0),0);
  const ps=calcPP(ords),tGP=ps.reduce((s,x)=>s+x.profit,0);
  let sh;
  if(can('manageExpenses')){const exp=filterByPeriod(G('expenses')||[]);const tExp=exp.reduce((s,e)=>s+(e.amount||0),0);sh=buildStat('teal','trending-up',fC(tR),'إجمالي الإيرادات')+buildStat('purple','package',fC(tGP),'ربح المنتجات')+buildStat('red','receipt',fC(tExp),'المصروفات')+buildStat('gold','wallet',fC(tGP-tExp),'صافي الربح')}else{const avg=inv.length?Math.round(tR/inv.length):0;sh=buildStat('teal','trending-up',fC(tR),'الإيرادات')+buildStat('gold','file-text',inv.length,'الفواتير')+buildStat('blue','bar-chart-3',fC(avg),'المتوسط')+buildStat('purple','calendar',fC(tR),'مبيعات الفترة')}
  document.getElementById('repSt').innerHTML=sh;

  // Doughnut
  const cm={};ords.forEach(o=>(o.items||[]).forEach(it=>{const p=(G('products')||[]).find(x=>x.id===it.productId);cm[p?.category||'أخرى']=(cm[p?.category||'أخرى']||0)+it.price*it.qty}));
  const ctx=document.getElementById('cRep').getContext('2d');if(cR)cR.destroy();
  cR=Object.keys(cm).length?new Chart(ctx,{type:'doughnut',data:{labels:Object.keys(cm),datasets:[{data:Object.values(cm),backgroundColor:['#D4AF37','#2DD4BF','#60A5FA','#A78BFA','#F04F4F','#FBBF24'],borderColor:'#131722',borderWidth:3}]},options:{responsive:true,maintainAspectRatio:false,cutout:'68%',plugins:{legend:{position:'bottom',labels:{color:'#8E9AAF',font:{family:'Cairo',size:12},padding:14,usePointStyle:true}}}}}):new Chart(ctx,{type:'doughnut',data:{labels:['لا بيانات'],datasets:[{data:[1],backgroundColor:['#232837'],borderWidth:0}]},options:{responsive:true,maintainAspectRatio:false,cutout:'68%',plugins:{legend:{display:false}}}});

  // Bar chart
  const ctx2=document.getElementById('cRepBar').getContext('2d');if(cRBar)cRBar.destroy();
  if(repPeriodMode==='monthly'){const dim=new Date(repYear,repMonth+1,0).getDate();const labels=[],data=[];for(let d=1;d<=dim;d++){labels.push(d);const ds=`${repYear}-${String(repMonth+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;data.push(inv.filter(v=>v.date&&v.date.startsWith(ds)).reduce((s,v)=>s+(v.grandTotal||0),0))}const gr2=ctx2.createLinearGradient(0,0,0,200);gr2.addColorStop(0,'rgba(212,175,55,0.6)');gr2.addColorStop(1,'rgba(212,175,55,0.1)');cRBar=new Chart(ctx2,{type:'bar',data:{labels,datasets:[{data,backgroundColor:gr2,borderColor:'#D4AF37',borderWidth:1,borderRadius:4}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},scales:{x:{grid:{display:false},ticks:{color:'#8E9AAF',font:{family:'Inter',size:10},maxRotation:0,autoSkip:true,maxTicksLimit:15}},y:{grid:{color:'rgba(255,255,255,0.03)'},ticks:{color:'#8E9AAF',font:{family:'Inter'}}}}}})
  }else{const labels=monthNames.map(m=>m.substring(0,3));const data=[];for(let m=0;m<12;m++){const prefix=`${repYear}-${String(m+1).padStart(2,'0')}`;data.push(allInv.filter(v=>v.date&&v.date.startsWith(prefix)).reduce((s,v)=>s+(v.grandTotal||0),0))}const gr2=ctx2.createLinearGradient(0,0,0,200);gr2.addColorStop(0,'rgba(212,175,55,0.6)');gr2.addColorStop(1,'rgba(212,175,55,0.1)');cRBar=new Chart(ctx2,{type:'bar',data:{labels,datasets:[{data,backgroundColor:gr2,borderColor:'#D4AF37',borderWidth:1,borderRadius:6}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},scales:{x:{grid:{display:false},ticks:{color:'#8E9AAF',font:{family:'Cairo',size:11}}},y:{grid:{color:'rgba(255,255,255,0.03)'},ticks:{color:'#8E9AAF',font:{family:'Inter'}}}}}})}

  // Compare chart
  const ctx3=document.getElementById('cRepCompare').getContext('2d');if(cRCompare)cRCompare.destroy();
  if(can('manageExpenses')){const allExp=G('expenses')||[];
    if(repPeriodMode==='monthly'){const dim=new Date(repYear,repMonth+1,0).getDate();const revD=[],expD=[],lbl=[];for(let d=1;d<=dim;d++){lbl.push(d);const ds=`${repYear}-${String(repMonth+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;revD.push(inv.filter(v=>v.date&&v.date.startsWith(ds)).reduce((s,v)=>s+(v.grandTotal||0),0));expD.push(allExp.filter(e=>e.date&&e.date.startsWith(ds)).reduce((s,e)=>s+(e.amount||0),0))}const grR=ctx3.createLinearGradient(0,0,0,200);grR.addColorStop(0,'rgba(45,212,191,0.15)');grR.addColorStop(1,'rgba(45,212,191,0)');const grE=ctx3.createLinearGradient(0,0,0,200);grE.addColorStop(0,'rgba(240,79,79,0.15)');grE.addColorStop(1,'rgba(240,79,79,0)');cRCompare=new Chart(ctx3,{type:'line',data:{labels:lbl,datasets:[{label:'الإيرادات',data:revD,borderColor:'#2DD4BF',backgroundColor:grR,fill:true,tension:.4,pointRadius:2,borderWidth:2},{label:'المصروفات',data:expD,borderColor:'#F04F4F',backgroundColor:grE,fill:true,tension:.4,pointRadius:2,borderWidth:2}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom',labels:{color:'#8E9AAF',font:{family:'Cairo',size:12},padding:14,usePointStyle:true}}},scales:{x:{grid:{display:false},ticks:{color:'#8E9AAF',font:{family:'Inter',size:10},maxRotation:0,autoSkip:true,maxTicksLimit:15}},y:{grid:{color:'rgba(255,255,255,0.03)'},ticks:{color:'#8E9AAF',font:{family:'Inter'}}}}}})
    }else{const revD=[],expD=[];for(let m=0;m<12;m++){const prefix=`${repYear}-${String(m+1).padStart(2,'0')}`;revD.push(allInv.filter(v=>v.date&&v.date.startsWith(prefix)).reduce((s,v)=>s+(v.grandTotal||0),0));expD.push(allExp.filter(e=>e.date&&e.date.startsWith(prefix)).reduce((s,e)=>s+(e.amount||0),0))}const grR=ctx3.createLinearGradient(0,0,0,200);grR.addColorStop(0,'rgba(45,212,191,0.15)');grR.addColorStop(1,'rgba(45,212,191,0)');const grE=ctx3.createLinearGradient(0,0,0,200);grE.addColorStop(0,'rgba(240,79,79,0.15)');grE.addColorStop(1,'rgba(240,79,79,0)');cRCompare=new Chart(ctx3,{type:'line',data:{labels:monthNames.map(m=>m.substring(0,3)),datasets:[{label:'الإيرادات',data:revD,borderColor:'#2DD4BF',backgroundColor:grR,fill:true,tension:.4,pointRadius:3,borderWidth:2},{label:'المصروفات',data:expD,borderColor:'#F04F4F',backgroundColor:grE,fill:true,tension:.4,pointRadius:3,borderWidth:2}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom',labels:{color:'#8E9AAF',font:{family:'Cairo',size:12},padding:14,usePointStyle:true}}},scales:{x:{grid:{display:false},ticks:{color:'#8E9AAF',font:{family:'Cairo',size:11}}},y:{grid:{color:'rgba(255,255,255,0.03)'},ticks:{color:'#8E9AAF',font:{family:'Inter'}}}}}})}
  }else{cRCompare=new Chart(ctx3,{type:'doughnut',data:{labels:['لا بيانات'],datasets:[{data:[1],backgroundColor:['#232837'],borderWidth:0}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}}}})}

  const srt=[...inv].sort((a,b)=>new Date(b.date)-new Date(a.date));
  document.getElementById('invLst').innerHTML=srt.length?srt.slice(0,12).map(i=>`<div class="invoice-row"><div><div class="inv-title">فاتورة #${i.id} · طاولة ${i.tableNumber||'—'}</div><div class="inv-meta">${fT(i.date)} · ${fD(i.date)}</div></div><div class="inv-amount">${fC(i.grandTotal)}</div></div>`).join(''):'<div style="text-align:center;padding:24px;color:var(--text-3)">لا توجد فواتير في هذه الفترة</div>';
  const byProfit=[...ps].sort((a,b)=>b.profit-a.profit).slice(0,5);document.getElementById('topProfit').innerHTML=byProfit.length?byProfit.map((p,i)=>`<div class="rank-item"><div class="rank-num">${i+1}</div><div class="rank-name">${esc(p.name)}</div><div class="rank-value">${fC(p.profit)}</div></div>`).join(''):'<div style="text-align:center;padding:24px;color:var(--text-3)">لا توجد بيانات</div>';
  const bySales=[...ps].sort((a,b)=>b.qtySold-a.qtySold).slice(0,5);document.getElementById('topSellers').innerHTML=bySales.length?bySales.map((p,i)=>`<div class="rank-item"><div class="rank-num">${i+1}</div><div class="rank-name">${esc(p.name)}</div><div class="rank-value">×${p.qtySold}</div></div>`).join(''):'<div style="text-align:center;padding:24px;color:var(--text-3)">لا توجد بيانات</div>';ri()
};

const renderAllInv=()=>{const inv=filterByPeriod(G('invoices')||[]);const srt=[...inv].sort((a,b)=>new Date(b.date)-new Date(a.date));const pl=repPeriodMode==='monthly'?`${monthNames[repMonth]} ${repYear}`:`سنة ${repYear}`;document.getElementById('invPeriodMeta').textContent=`${inv.length} فاتورة · ${pl}`;document.getElementById('allInvLst').innerHTML=srt.length?srt.map(i=>{const c=i.status==='cancelled';return`<div class="invoice-row"><div><div class="inv-title">فاتورة #${i.id} · طاولة ${i.tableNumber||'—'} ${c?'<span class="badge badge-red">ملغاة</span>':''}</div><div class="inv-meta">${fT(i.date)} · ${fD(i.date)}</div></div><div style="display:flex;align-items:center;gap:12px"><div class="inv-amount ${c?'cancelled':''}">${fC(i.grandTotal)}</div>${can('cancelInvoice')&&!c?`<button class="btn btn-danger btn-sm" onclick="cancelInvoice(${i.id})">إلغاء</button>`:''}</div></div>`}).join(''):`<div class="empty-state">${ic('file-x',48)}<div class="empty-state-title">لا توجد فواتير في هذه الفترة</div></div>`;ri()};

const cancelInvoice=id=>modal(`<div class="modal-title">إلغاء الفاتورة #${id}</div><div class="modal-subtitle">هل أنت متأكد؟</div><div class="modal-footer"><button class="btn btn-ghost" onclick="closeM()">تراجع</button><button class="btn btn-danger" onclick="doCancelInv(${id})">إلغاء</button></div>`);const doCancelInv=id=>{UP('invoices',id,{status:'cancelled',cancelledAt:new Date().toISOString(),cancelledBy:CU?.id});addA(`إلغاء فاتورة #${id}`,'#F04F4F');toast('تم الإلغاء');closeM();renderAllInv()};

const renderExpenses=()=>{const exp=filterByPeriod(G('expenses')||[]);const srt=[...exp].sort((a,b)=>new Date(b.date)-new Date(a.date));const pl=repPeriodMode==='monthly'?`${monthNames[repMonth]} ${repYear}`:`سنة ${repYear}`;const tE=exp.reduce((s,e)=>s+(e.amount||0),0);document.getElementById('expPeriodMeta').textContent=`${exp.length} مصروف · ${fC(tE)} · ${pl}`;document.getElementById('expLst').innerHTML=srt.length?srt.map(e=>`<div class="expense-row"><div><div class="exp-title">${esc(e.title)}</div><div class="exp-meta">${esc(e.category||'عام')} · ${fD(e.date)}${e.notes?' · '+esc(e.notes):''}</div></div><div style="display:flex;align-items:center;gap:12px"><div class="exp-amount">− ${fC(e.amount)}</div><button class="btn btn-danger btn-sm" onclick="confDel('expenses',${e.id},'${esc(e.title).replace(/'/g,"\\'")}')">${ic('trash-2')}</button></div></div>`).join(''):`<div class="empty-state">${ic('receipt',48)}<div class="empty-state-title">لا توجد مصروفات في هذه الفترة</div></div>`;ri()};

const openExpM=()=>modal(`<div class="modal-title">تسجيل مصروف</div><div class="input-group"><label>الوصف</label><div class="input-wrap"><input id="eTi" placeholder="فاتورة كهرباء"></div></div><div class="form-row"><div class="input-group"><label>المبلغ</label><div class="input-wrap"><input type="number" id="eAmt" placeholder="0"></div></div><div class="input-group"><label>الفئة</label><div class="input-wrap"><select id="eCat"><option>عام</option><option>إيجار</option><option>كهرباء/ماء</option><option>رواتب</option><option>مشتريات</option><option>صيانة</option></select></div></div></div><div class="form-row"><div class="input-group"><label>التاريخ</label><div class="input-wrap"><input type="date" id="eDt" value="${td()}"></div></div><div class="input-group"><label>ملاحظات</label><div class="input-wrap"><input id="eNt" placeholder="اختياري"></div></div></div><div class="modal-footer"><button class="btn btn-ghost" onclick="closeM()">إلغاء</button><button class="btn btn-gold" onclick="saveExp()">حفظ</button></div>`);const saveExp=()=>{const ti=document.getElementById('eTi').value.trim(),amt=parseFloat(document.getElementById('eAmt').value);if(!ti){toast('أدخل الوصف','err');return}if(!amt||amt<=0){toast('أدخل مبلغاً صحيحاً','err');return}const exp=G('expenses')||[];exp.push({id:NI('expenses'),title:ti,amount:amt,category:document.getElementById('eCat').value,date:document.getElementById('eDt').value,notes:document.getElementById('eNt').value.trim(),createdBy:CU?.id,createdAt:new Date().toISOString()});S('expenses',exp);addA(`مصروف: ${ti} — ${fC(amt)}`,'#F04F4F');toast('تمت الإضافة');closeM();renderExpenses()};

/* Settings */
const renderSet=()=>{const i=G('ri')||{};document.getElementById('sNm').value=i.name||'';document.getElementById('sCr').value=i.currency||'ل.ع';document.getElementById('sTx').value=i.tax||0;document.getElementById('sPh').value=i.phone||'';document.getElementById('sAd').value=i.address||'';renderUsrs()};const saveSet=()=>{S('ri',{name:document.getElementById('sNm').value.trim(),currency:document.getElementById('sCr').value.trim(),tax:parseFloat(document.getElementById('sTx').value)||0,phone:document.getElementById('sPh').value.trim(),address:document.getElementById('sAd').value.trim()});document.getElementById('sbRn').textContent=document.getElementById('sNm').value||'—';toast('تم حفظ الإعدادات')};const renderUsrs=()=>{const us=G('users')||[],rA={manager:'مدير',cashier:'كاشير',waiter:'نادل',kitchen:'مطبخ'};document.getElementById('usrBd').innerHTML=us.map(u=>`<tr><td><strong style="color:var(--text)">${esc(u.name)}</strong></td><td style="color:var(--text-2);font-size:12px">${esc(u.email)}</td><td><span class="badge badge-muted">${rA[u.role]||u.role}</span></td><td><div style="display:flex;gap:6px;justify-content:flex-end">${u.id!==CU?.id?`<button class="btn btn-ghost btn-sm" onclick="openUsrM(${u.id})">${ic('edit-3')}</button><button class="btn btn-danger btn-sm" onclick="confDel('users',${u.id},'${esc(u.name).replace(/'/g,"\\'")}')">${ic('trash-2')}</button>`:'<span style="font-size:11px;color:var(--text-3)">أنت</span>'}</div></td></tr>`).join('');ri()};const openUsrM=(id=null)=>{const us=G('users')||[],u=id?us.find(x=>x.id===id):null;modal(`<div class="modal-title">${u?'تعديل مستخدم':'مستخدم جديد'}</div><div class="input-group"><label>الاسم</label><div class="input-wrap"><input id="uNmI" value="${esc(u?.name||'')}"></div></div><div class="input-group"><label>البريد</label><div class="input-wrap"><input type="email" id="uEm" value="${esc(u?.email||'')}"></div></div><div class="input-group"><label>كلمة المرور</label><div class="input-wrap"><input type="password" id="uPw" value="${esc(u?.password||'')}"></div></div><div class="input-group"><label>الدور</label><div class="input-wrap"><select id="uRlSel"><option value="manager" ${u?.role==='manager'?'selected':''}>مدير</option><option value="cashier" ${u?.role==='cashier'?'selected':''}>كاشير</option><option value="waiter" ${u?.role==='waiter'?'selected':''}>نادل</option><option value="kitchen" ${u?.role==='kitchen'?'selected':''}>مطبخ</option></select></div></div><div class="modal-footer"><button class="btn btn-ghost" onclick="closeM()">إلغاء</button><button class="btn btn-gold" onclick="saveUsr(${id||'null'})">حفظ</button></div>`)};const saveUsr=id=>{const nm=document.getElementById('uNmI').value.trim(),em=document.getElementById('uEm').value.trim(),pw=document.getElementById('uPw').value;if(!nm||!em||!pw){toast('أكمل الحقول','err');return}const us=G('users')||[];if(!id&&us.find(u=>u.email===em)){toast('البريد مستخدم','err');return}const d={name:nm,email:em,password:pw,role:document.getElementById('uRlSel').value};if(id){UP('users',id,d);toast('تم التعديل')}else{us.push({id:NI('users'),...d});S('users',us);toast('تمت الإضافة')}closeM();renderUsrs()};const resetAll=()=>{if(confirm('هل أنت متأكد؟ سيتم حذف كل البيانات نهائياً.')){localStorage.clear();toast('جارٍ إعادة التحميل...','info');setTimeout(()=>location.reload(),1500)}};
/* Export */
const exportProductsExcel=()=>{const pr=G('products')||[];const data=pr.map(p=>({'رقم':p.code||'','الاسم':p.name,'الفئة':p.category||'','التكلفة':p.cost||0,'البيع':p.price||0,'الربح':(p.price||0)-(p.cost||0)}));const ws=XLSX.utils.json_to_sheet(data),wb=XLSX.utils.book_new();XLSX.utils.book_append_sheet(wb,ws,'المنتجات');XLSX.writeFile(wb,`RestroHub_${td()}.xlsx`);toast('تم التصدير')};const exportProductsPDF=()=>{try{const{jsPDF}=window.jspdf,doc=new jsPDF({orientation:'landscape'});doc.setFontSize(16);doc.text('RestroHub - Products',14,15);doc.setFontSize(10);doc.text(`Date: ${fD(new Date().toISOString())}`,14,22);const pr=G('products')||[],rows=pr.map(p=>[p.code||'-',p.name,p.category||'-',(p.cost||0).toLocaleString(),(p.price||0).toLocaleString(),((p.price||0)-(p.cost||0)).toLocaleString()]);doc.autoTable({head:[['Code','Name','Category','Cost','Price','Profit']],body:rows,startY:28,styles:{fontSize:9},headStyles:{fillColor:[212,175,55],textColor:11}});doc.save(`RestroHub_${td()}.pdf`);toast('تم التصدير')}catch(e){console.error(e);toast('خطأ','err')}};
/* Boot */
seed();
